import{_ as e,o as a,c as b,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"魔剑士","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/魔剑士.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/魔剑士.md"}'),o={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/魔剑士.md"};function s(d,p,l,_,i,B){return a(),b("div",null,[...p[0]||(p[0]=[r("h1",{id:"魔剑士",tabindex:"-1"},[t("魔剑士 "),r("a",{class:"header-anchor",href:"#魔剑士","aria-label":'Permalink to "魔剑士"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="魔剑士-1" tabindex="-1">魔剑士 <a class="header-anchor" href="#魔剑士-1" aria-label="Permalink to &quot;魔剑士&quot;">​</a></h1><p>魔剑士<br> （一次性改造）<br> 前置：学识3或以上<br> 描述：“魔剑士”=虽然是魔术师通过肉体强化特化了近战能力。<br> 话虽如此，但一般也只是通过强化反射神经，强化肉体达到足以使用被魔术强化的各类武具尤其是刀剑类别压倒性多的职业。</p><p>作为异类的“魔剑士”一族要说起源的话大概正是来自于所谓的“魔剑”。使用血祭使用活祭、使用人祭。从钢、铁、金、银、秘银、山铜、奥利哈钢这样的金属到狮子、龙、狼……兽类，幻想种以这样的生物作为素材在所谓“魔剑”道路上的不断精进。</p><p>金属有着固定的刚韧性，生物秦材制作的部位亦是从诞生之初便决定好的最后在终于开始了思考“人”本身为何不能是一种血肉构成的“剑”呢？<br> 会自己学习，不断成长，在“魔术刻印”的诞生之后甚至连肉体本身都能加以调整也就是可以昂首挺胸的说，成品的品质完全取决于“匠人”手艺。</p><p>这样对比起其他素材稍显不足，但拥有弥足珍贵的成长性的秦材。最后让这一族确定了道路，魔剑与剑士一体的魔术。</p><p>D级<br> 【魔术师】：虽然是偏道，但“魔剑士”其本质上依然是“魔术师”，拥有魔术回路，学习魔术，使用魔术，接受魔术刻印的存在。因此，你开启了【魔术回路】，并提升1级学识上的施法专业（若施法专业抵达3级或3级以上，则改为在学识相关检定上获得1DP修行加值）。</p><p>【魔术回路】：所谓魔术回路就是魔术师体内制造魔力的源泉。能够将生命力转化为魔力，作为施展魔术所需的能量基础而存在。</p><p>魔术回路本身视为魔力池的变种，在获得魔术回路后，你将获得等同自身（耐力+智力）*1条魔术回路，每1条魔术回路可以在计算能量消耗时为你提供1点能量，因此获得的能量视为【魔力】。当使用过魔术回路对应的魔力后，那些魔术回路会暂时失效，视为你耗尽了其中蕴含的个人魔力。</p><p>恢复方式：<br> 1、经过一次完整的长休息后，恢复所有失效的魔术回路。<br> 2、经过一次短休息后，恢复关键属性（耐力/智力）较高者*1条失效的魔术回路。<br> 3、消费一个自由动作，承受等同自身传奇耐力*6点不可避免的严重伤害，随后在本轮内获得传奇耐力*1点临时魔力。</p><p>无论如何，每日因上述恢复方式获得的魔力不会超过魔术回路数量的三倍。</p><p>【人形兵器】：字面意义上的意思，以最大限度、根本上的调整和魔术强化使肉身更接近于兵器。<br> 尽管如此，既没有到达“魔剑”的强度，亦缺乏作为剑士的素质。但反过来说，既是超过了“魔剑”的灵活，又具有大部分剑士以上的身体水准。</p><p>你在生理属性/心智属性/社交属性合计每有3点传奇属性，则所有天生武器的伤害就会提升1L。从现在开始，你的天生武器只能用来施展刀剑类技艺，同时只能享受刀剑类效果带来的好处（但提升天生武器伤害的效果可以正常获得），你必须在购买本改造时选择一种刀剑武器类型，在施展刀剑类技艺或满足前置效果时将自身天生武器视为选择的刀剑武器类型处理（如：短剑，迅捷剑，长剑，重剑等）。</p><p>【魔剑士下属能力】</p><p>回路强化（D，C，B）<br> 价格：D+500/C+2000/B+3000（逐级提升）<br> 分类：被动<br> 描述：魔术师特有的体内模拟神经，作为基盘也是联系大魔术式的道路，连接灵体和物质的回路是魔术师体内持有的拟似神秘。只要有魔术回路，就拥有可以弹飞催眠、咒缚之类的干涉魔术的抗魔力。<br> 虽说魔术回路的数量是生来就决定好了，不会因外在因素而增加，但也有没能激活的潜藏回路以及人工制造的类魔力回路等情况。<br> 效果：<br> 根据回路强化等级，你免疫D/C/B级由魔力推动的负面效果（对应D/C/B级）。此外，你还会在不同等级获得对应效果。<br> ——<br> D级：<br> *每小时一次，你可以进行一次能量池关键属性检定，恢复成功数*1条魔术回路，这会计入每日的恢复上限。<br> *对于魔术回路，你获得了新的基础用法：支付2点魔力，在该场景内你的天生武器获得【法破】特性。<br> ——<br> C级：在这一等级，你必须从分支中选择其中之一的效果获得，替换D级效果。<br> 【质】：每轮一次，你在使用魔力时消耗减少等同传奇耐力-1点（下限1点），同时每小时一次，你可以进行一次能量池关键属性检定，恢复成功数*1条魔术回路，这会计入每日的恢复上限。<br> 【量】：你的魔术回路增加等同自身耐力*1条。<br> 对于魔术回路，你获得了新的基础用法：<br> *支付6点魔力，在该场景内你的天生武器获得【法破】特性，在生理属性相关检定上获得传奇耐力*2点增强加值。<br> ——<br> B级：保留C级效果，同时你可以从地，火，水，风中选择一项作为自己的魔术属性，并获得对应效果。</p><p>【地】：象征稳固与物质，与生命和死的概念相关，擅长结合或改变形态的魔术。作为魔剑士而言，选择这一属性会使你的攻击附带【重伤B】，并使你在进行具有“安定”、“坚固”、”重力”、“物质”、“形态”、“结合”、“承载”、“丰饶”、“不动”的相关词缀施法检定中获得5DP增强加值。</p><p>【水】：代表流动与变化，特性为“吸收”。作为魔剑士而言，选择这一属性会在你进行攻击时附带【传奇智力】*1点【吸血】，并使你在进行“流动”、“循环”、“变化”、“融合”、“净化”、“治愈”、“生命”、“适应”、“精神”相关词缀的施法检定中获得5DP增强加值。</p><p>【火】：具有破坏性，被称为“Normal”属性，与攻击性魔术相性良好。作为魔剑士而言，选择这一属性会使你的攻击具有【幻灭】特性，并使你在进行所有攻击类施法检定中获得5DP增强加值。</p><p>【风】：被称为“Noble”属性，特性与天体运行相关，代表“运动与情报，以及空间的自由”。作为魔剑士而言，选择这一属性会使你的视为具有B级时空来源的传送攻击能力，并使你在进行“自由”、“运动”、“气体”、“声音”、“切割”、“传递”、“情报”、“空间”、“锐利”、“轻盈”相关词缀的施法检定中获得5DP增强加值。</p><p>魔术刻印（D，C，B）<br> 价格：D+500/C+1000/B+2000（逐级提升）<br> 描述：所谓魔术刻印，可是说是与魔术师本人的回路所不同的附属引擎。刻在里面的魔术，只要魔力流过就能发动。不需要复杂的咏唱手续。运转起来就可以使魔术这辆车跑动，终极的加速装置。是刻有自魔术师家系的始祖起直至现在的所有研究成果的“应当继承的遗产”。<br> 效果：<br> 由于魔术刻印的本质是“外置器官”，初代由幻想种或是魔术礼装的碎片植入体内来制作，因此魔术刻印本身不视为内在强化，而是永久性占据你护符位的奇物。由于魔术刻印与使用者本身高度绑定，不经过特殊的魔术手段就无法拆除，因此你无法将这一奇物移交给他人。</p><p>魔术刻印会为你提供等同等级B/A/S级免疫夺权来源效果的能力，并根据魔术刻印等级，你在学识技能下的任一施法所用专业上获得1/2/5级提升，并获得学识技能检定上的2/4/6点器械加值与1个额外附加成功。</p><p>购买魔术刻印后，由回路强化带来的加值可以永久性改为在使用具有相关词缀近战类能力时生效。<br> ——<br> 在不同等级，魔术刻印还会提供特定的能力。<br> C级：你获得固有魔术：【魔剑解放】。</p><p>【魔剑解放】：短暂的还原与自身一体化的魔剑形态，像是魔力放出一样、不仅能提高威力，还能提升攻击距离。</p><p>迅捷动作启动，支付6点魔力，该场景内可以使用力量取代智力进行施法检定，你的攻击触及距离提升等同自身传奇智力*4米的距离，在攻击上获得2点增强加值与1个额外附加成功数。</p><p>B级：购买B级魔术刻印需要已经具有B级回路强化，此时根据B级回路强化选择的属性，将C级提供的【魔剑解放】改为对应属性的元素魔剑，如选择了地属性，则效果改为【地之魔剑】等等，因此你只会获得一种对应的元素魔剑。<br> 启动元素魔剑是一个迅捷动作，需要消费10点魔力，视为使用了【魔剑解放】一般获得相应好处，此外会根据元素的属性获得下列好处，同样持续一场景。</p><p>【地之魔剑】：从现在开始，地属性带来的【重伤B】不仅会使被攻击者的伤势无法自动稳定，也会导致其在处理恢复效果时，不超过3点的快速医疗/效果转为扣除生命值。</p><p>此外，你的攻击触及距离提升等同自身传奇智力*10米，在攻击上获得4点增强加值与1个额外附加成功数，你免疫B级别困难地形效果。</p><p>【水之魔剑】：获得这一效果前你需要指定自身耐力或智力属性，并选择能量、偏斜或天生防御其中之一。你在选择的那种防御上获得选择属性一半的提升，并且获得基于对应防御的【适应】。</p><p>此外，水之魔剑启动后的攻击触及距离提升等同自身传奇智力*5米，可以对触及范围内的所有敌人进行攻击，并且攻击额外获得1个附加成功数。</p><p>【火之魔剑】：启动火之魔剑的动作是移动而非迅捷动作，启动后你的近战攻击造成的伤害翻倍，这一效果每轮只会生效一次。此外，你的攻击触及距离提升等同自身传奇智力*5米。</p><p>【风之魔剑】：你获得B级时空来源的传送移动能力，你的移动速度提升等同自身智力*3米并获得机动性为完美的飞行能力。</p><p>肉锻！<br> 价格：C+1500<br> 分类：被动<br> 描述：基本上是通过反复对抗，捶打，的原理结合魔术，通过各种方式来提升“成品”水平的秘技。<br> 效果：在影片内若你经历过一场同级难度的战斗，就会在影片结束时提升2L天生武器伤害，以及使天生防御提升2点，你最多因此获得【传奇耐力】*【传奇力量】次提升。</p><p>匠人<br> 价格：C+1500<br> 分类：被动<br> 描述：即使将大部分的精力和技艺投入到最大的作品（锻炼身体）之中，依然是一位可以说素质精良的匠人。<br> 效果：你可以使用力量取代智力进行制造物品；每经历一场影片，你在造物相关检定上获得1个额外附加成功数。</p><p>胜负一筋！<br> 价格：B+4000<br> 分类：被动<br> 描述：一心不乱地追求自身肉体的进步，斩击、钝击、刺击、魔术、技术、异数——如果不堂堂正正发起挑战，就无法真正认识自己的肉体。如同尝试使用斩击断绝流水、切开火焰般，摒弃所谓的胜负和可行性。单纯如同求知一般挑战“业”之人持有的证明。<br> 效果：<br> *你只能使用【力量】作为攻击的主属性，这意味着任何能为你带来改变使用主属性攻击的效果，你都无法享受对应的好处。不过，你会在力量相关检定上获得6DP修行加值与2个额外附加成功数。<br> *当你的攻击命中时，目标必须使用意志豁免对抗你的攻击伤害出目，失败则在该场景内需要使用【力量】作为攻击主属性，这是一个B级创伤来源的胁迫效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',35)])])}const D=e(o,[["render",s]]);export{h as __pageData,D as default};
